const SUPABASE_URL = 'https://lahqlyaxvobqjgdiftag.supabase.co';
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
const parsed = $('Parsear Mensaje').first().json;
const phone = parsed.normalized_phone;

const profileResp = await this.helpers.httpRequest({
  method: 'GET',
  url: `${SUPABASE_URL}/rest/v1/profiles?phone=eq.${phone}&select=user_id,full_name`,
  headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` },
  json: true
});

if (!profileResp || profileResp.length === 0) {
  return [{ json: {
    matched: false, reason: 'telefono_no_registrado',
    from: parsed.from, normalized_phone: phone, phone_number_id: parsed.phone_number_id
  }}];
}

const userId = profileResp[0].user_id;
const memberResp = await this.helpers.httpRequest({
  method: 'GET',
  url: `${SUPABASE_URL}/rest/v1/org_members?user_id=eq.${userId}&estado=eq.activo&select=org_id`,
  headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` },
  json: true
});

if (!memberResp || memberResp.length === 0) {
  return [{ json: {
    matched: false, reason: 'sin_org',
    from: parsed.from, normalized_phone: phone, phone_number_id: parsed.phone_number_id
  }}];
}

const orgIds = memberResp.map(m => m.org_id);
const orgsResp = await this.helpers.httpRequest({
  method: 'GET',
  url: `${SUPABASE_URL}/rest/v1/organizations?id=in.(${orgIds.join(',')})&select=id,nombre,settings`,
  headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` },
  json: true
});

if (!orgsResp || orgsResp.length === 0) {
  return [{ json: {
    matched: false, reason: 'sin_org',
    from: parsed.from, normalized_phone: phone, phone_number_id: parsed.phone_number_id
  }}];
}

const resolvedOrg = orgsResp[0];
const resolvedSettings = resolvedOrg.settings || {};

async function rpcOrgHasFeature(orgId, featureId) {
  const r = await this.helpers.httpRequest({
    method: 'POST',
    url: `${SUPABASE_URL}/rest/v1/rpc/org_has_feature`,
    headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}`, 'Content-Type': 'application/json' },
    body: { p_org_id: orgId, p_feature_id: featureId },
    json: true
  });
  return r === true;
}




return [{ json: {
  matched: true,
  org_id: resolvedOrg.id,
  org_nombre: resolvedOrg.nombre,
  user_id: userId,
  from: parsed.from,
  normalized_phone: phone,
  phone_number_id: parsed.phone_number_id,
  media_id: parsed.media_id,
  mime_type: parsed.mime_type
}}];

