  filename: null,
  text_body: null,
  button_reply_id: null,
  button_reply_title: null
};

switch (msg.type) {
  case 'image':
    result.media_id = msg.image.id;
    result.mime_type = msg.image.mime_type;
    result.caption = msg.image.caption || null;
    result.filename = `whatsapp-${msg.from}-${Date.now()}.jpg`;
    break;
  case 'document':
    result.media_id = msg.document.id;
    result.mime_type = msg.document.mime_type;
    result.caption = msg.document.caption || null;
    result.filename = msg.document.filename || `whatsapp-${msg.from}-${Date.now()}.pdf`;
    break;
  case 'audio':
    result.media_id = msg.audio.id;
    result.mime_type = msg.audio.mime_type;
    result.filename = `voice-${msg.from}-${Date.now()}.ogg`;
    break;
  case 'text':
    result.text_body = msg.text?.body || null;
    break;
  case 'interactive':
    if (msg.interactive?.type === 'button_reply') {
      result.button_reply_id = msg.interactive.button_reply.id;
      result.button_reply_title = msg.interactive.button_reply.title;
    }
    break;
}


return [{ json: result }];

// Config
const SUPABASE_URL = 'https://lahqlyaxvobqjgdiftag.supabase.co';
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;

