const parsed = $('Parsear Mensaje').first().json;
const normalized = parsed.normalized_phone;

const resp = await this.helpers.httpRequest({
  method: 'GET',
  url: `${SUPABASE_URL}/rest/v1/organizations?settings-%3Ewhatsapp-%3E%3Ephone_number=eq.${normalized}&select=id,nombre`,
  headers: {
    'apikey': SUPABASE_KEY,
    'Authorization': `Bearer ${SUPABASE_KEY}`
  },
  json: true
});

const org = resp?.[0] || {};

return [{ json: {
  correction_text: parsed.text_body,
  normalized_phone: normalized,
  raw_from: parsed.from,
  phone_number_id: parsed.phone_number_id,
  org_id: org.id || '',
  org_nombre: org.nombre || ''
}}];

const buttonId = $('Parsear Mensaje').first().json.button_reply_id;

let intent;
if (buttonId === 'voice_confirm') intent = 'confirm';
else if (buttonId === 'voice_cancel') intent = 'cancel';
else if (buttonId === 'voice_correct') intent = 'correct';
else intent = 'unknown';

return [{ json: {
  session_id_hash: $('Hash Session').first().json.session_id_hash,
  intent,
  normalized_phone: $('Parsear Mensaje').first().json.normalized_phone,
  raw_from: $('Parsear Mensaje').first().json.from,
  phone_number_id: $('Parsear Mensaje').first().json.phone_number_id
}}];

const SUPABASE_URL = 'https://lahqlyaxvobqjgdiftag.supabase.co';
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
const rows = $input.all();
if (!rows.length) return [{ json: { error: true, message: 'No hay sesion de factura activa.' } }];

let raw = '';
for (const row of rows) {
  const msg = row.json && row.json.message;
  if (!msg) continue;
  const msgObj = typeof msg === 'string' ? JSON.parse(msg) : msg;
  if (msgObj.type === 'ai' || msgObj.type === 'AIMessage' || msgObj.type === 'assistant') {
    raw = (msgObj.data && msgObj.data.content) || msgObj.content || (typeof msg === 'string' ? msg : JSON.stringify(msg));
    break;
  }
}

if (!raw) {
  const firstMsg = rows[0] && rows[0].json && rows[0].json.message;
  const debug = typeof firstMsg === 'string' ? firstMsg.substring(0, 200) : JSON.stringify(firstMsg).substring(0, 200);
  return [{ json: { error: true, message: 'No se encontro respuesta del agente. Debug: ' + debug } }];
}

let data;
try {
  const jsonMatch = raw.match(/\{[\s\S]*\}/);
  data = JSON.parse(jsonMatch ? jsonMatch[0] : raw);
} catch (e) {
  return [{ json: { error: true, message: 'JSON invalido del agente. Raw: ' + raw.substring(0, 200) } }];
}

const phone = $('Procesar Boton').first().json.normalized_phone;

// Profile-only resolution (phone -> user -> org)
const profileResp = await this.helpers.httpRequest({
  method: 'GET',
  url: `${SUPABASE_URL}/rest/v1/profiles?phone=eq.${phone}&select=user_id`,
  headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` },
  json: true
});
if (!profileResp || profileResp.length === 0) {
  return [{ json: { error: true, message: 'Tu telefono no esta registrado en ningun perfil de TuFacturaIA.' } }];
}
const user_id = profileResp[0].user_id;

const memberResp = await this.helpers.httpRequest({
  method: 'GET',
  url: `${SUPABASE_URL}/rest/v1/org_members?user_id=eq.${user_id}&estado=eq.activo&select=org_id`,
  headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` },
  json: true
});
if (!memberResp || memberResp.length === 0) {
  return [{ json: { error: true, message: 'No perteneces a ninguna organizacion activa.' } }];
}
const org_id = memberResp[0].org_id;

// ── BRANCH NUEVO: convertir_presupuesto ──
// Si el agente devolvió tipo='convertir_presupuesto', cortocircuitamos el flujo
// normal (no hay líneas que normalizar, no hay que llamar /api/voice/generate).
// El siguiente IF "Es Conversion?" detecta flow='convert_presupuesto' y enruta
// al nodo HTTP que llama /api/voice/convert-presupuesto.
if (data.tipo === 'convertir_presupuesto') {
  if (data.error) {
    return [{ json: { error: true, message: data.mensaje || 'No pude convertir el presupuesto.' } }];
  }
  if (!data.presupuesto_id) {
    return [{ json: { error: true, message: 'Falta presupuesto_id en la respuesta del agente.' } }];
  }
  return [{ json: {
    error: false,
    flow: 'convert_presupuesto',
    org_id, user_id,
    presupuesto_id: data.presupuesto_id,
    presupuesto_num: data.presupuesto_num || null,
    total_estimado: data.total_estimado || null,
    phone,
    chat_id: phone,
    raw_from: $('Procesar Boton').first().json.raw_from,
    phone_number_id: $('Procesar Boton').first().json.phone_number_id
  }}];
}

const lineas = (data.lineas || []).map(l => ({
  concepto: l.descripcion || l.concepto,
  cantidad: l.cantidad,
  precio_unitario: l.precio_unitario,
  iva_pct: l.iva_pct || 21,
  descuento_pct: l.descuento_pct || 0
}));

return [{ json: {
  error: false,
  flow: 'generate',
  org_id,
  user_id,
  tipo: data.tipo || 'factura',
  factura_origen_id: data.factura_origen_id || null,
  cliente: data.cliente,
  lineas,
  descuento_global_pct: data.descuento_global_pct || 0,
  notas: data.notas || null,
  phone,
  raw_from: $('Procesar Boton').first().json.raw_from,
  phone_number_id: $('Procesar Boton').first().json.phone_number_id
}}];

