parameters.jsCode:
// bot_state_machine_v1 — Idempotency Check (Parsear Mensaje / Buscar Org Voz)
//
// Llama internamente al endpoint message-idempotency-check preservando
// TODOS los campos del item upstream (spread). Devuelve añadido
// `is_duplicate` (boolean).
//
// Fail-open: si APP_URL/SERVICE_KEY faltan o la API cae, is_duplicate=false
// → IF posterior cae a FALSE → flujo normal. Mejor procesar un dup que
// silenciar mensajes reales.
const APP_URL = $env.APP_URL;
const SERVICE_KEY = $env.FACTURAIA_SERVICE_KEY;
const parsed = $('Parsear Mensaje').first().json;
const org = $('Buscar Org Voz').first().json;

const providerMessageId =
  parsed.provider_message_id
  || parsed.message_id
  || parsed.wamid
  || null;

const orgId = org?.org_id || null;

if (!APP_URL || !SERVICE_KEY || !providerMessageId) {
  return [{
    json: {
      ...parsed,
      org_id: orgId || parsed.org_id,
      org_nombre: org?.org_nombre || parsed.org_nombre,
      is_duplicate: false,
      idempotency_check_skipped: !providerMessageId
        ? 'no provider_message_id'
        : 'misconfig',
    },
  }];
}

try {
  const resp = await this.helpers.httpRequest({
    method: 'POST',
    url: `${APP_URL}/api/internal/voice/message-idempotency-check`,
    headers: {
      'x-service-key': SERVICE_KEY,
      'Content-Type': 'application/json',
    },
    body: {
      provider_message_id: providerMessageId,
      org_id: orgId,
    },
    json: true,
    timeout: 3000,
  });
  return [{
    json: {
      ...parsed,
      org_id: orgId || parsed.org_id,
      org_nombre: org?.org_nombre || parsed.org_nombre,
      is_duplicate: resp?.is_duplicate === true,
    },
  }];
} catch (err) {
  const errMsg = String((err && err.message) ? err.message : err).slice(0, 120);
  return [{
    json: {
      ...parsed,
      org_id: orgId || parsed.org_id,
      org_nombre: org?.org_nombre || parsed.org_nombre,
      is_duplicate: false,
      idempotency_check_error: errMsg,
    },
  }];
}

// bot_state_machine_v1 — terminal stop for duplicate message
// El webhook ya respondió 200 al recibir; no enviamos nada a Meta
// para evitar duplicar el mensaje al usuario final.
return [{ json: { stopped: true, reason: 'duplicate_message' } }];

// bot_state_machine_v1 — Resolver Chat State (Parsear Mensaje / Buscar Org Voz)
//
// GET al backend para recuperar el state previo (last_view, last_listado,
// current_doc, last_intent). Inyecta los campos al item preservando upstream.
//
// Fail-open: si la API cae, previous_state queda como null y el agente
// trabaja sin contexto previo.
const APP_URL = $env.APP_URL;
const SERVICE_KEY = $env.FACTURAIA_SERVICE_KEY;
const parsed = $('Parsear Mensaje').first().json;
const org = $('Buscar Org Voz').first().json;

// phone_e164_normalize_v1: añadir '+' si falta — endpoint exige E.164.
const _phRaw = (parsed.normalized_phone || '').trim();
const phoneUser = _phRaw && !_phRaw.startsWith('+') ? '+' + _phRaw.replace(/^\++/, '') : _phRaw;
const phoneReceptorId = parsed.phone_number_id || '';
const orgId = org?.org_id || parsed.org_id || '';

if (!APP_URL || !SERVICE_KEY || !phoneUser || !orgId) {
  return [{
    json: {
      ...parsed,
      org_id: orgId,
      org_nombre: org?.org_nombre || parsed.org_nombre,
      previous_state: null,
      previous_state_json: null,
    },
  }];
}

try {
  const qs = new URLSearchParams({
    phone_user: phoneUser,
    phone_receptor_id: phoneReceptorId,
    org_id: orgId,
  }).toString();
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url: `${APP_URL}/api/internal/voice/chat-state?${qs}`,
    headers: {
      'x-service-key': SERVICE_KEY,
    },
    json: true,
    timeout: 3000,
  });
  return [{
    json: {
      ...parsed,
      org_id: orgId,
      org_nombre: org?.org_nombre || parsed.org_nombre,
      previous_state: resp?.current_view ?? null,
      previous_state_json: resp?.state_json ?? null,
    },
  }];
} catch (err) {
  const errMsg = String((err && err.message) ? err.message : err).slice(0, 120);
  return [{
    json: {
      ...parsed,
      org_id: orgId,
      org_nombre: org?.org_nombre || parsed.org_nombre,
      previous_state: null,
      previous_state_json: null,
      chat_state_resolve_error: errMsg,
    },
  }];
}

// bot_state_machine_v1 — Idempotency Check (Parsear Mensaje / Buscar Org Texto)
//
// Llama internamente al endpoint message-idempotency-check preservando
// TODOS los campos del item upstream (spread). Devuelve añadido
// `is_duplicate` (boolean).
//
// Fail-open: si APP_URL/SERVICE_KEY faltan o la API cae, is_duplicate=false
// → IF posterior cae a FALSE → flujo normal. Mejor procesar un dup que
// silenciar mensajes reales.
const APP_URL = $env.APP_URL;
const SERVICE_KEY = $env.FACTURAIA_SERVICE_KEY;
const parsed = $('Parsear Mensaje').first().json;
const org = $('Buscar Org Texto').first().json;

const providerMessageId =
  parsed.provider_message_id
  || parsed.message_id
  || parsed.wamid
  || null;

const orgId = org?.org_id || null;

if (!APP_URL || !SERVICE_KEY || !providerMessageId) {
  return [{
    json: {
      ...parsed,
      org_id: orgId || parsed.org_id,
      org_nombre: org?.org_nombre || parsed.org_nombre,
      is_duplicate: false,
      idempotency_check_skipped: !providerMessageId
        ? 'no provider_message_id'
        : 'misconfig',
    },
  }];
}

try {
  const resp = await this.helpers.httpRequest({
    method: 'POST',
    url: `${APP_URL}/api/internal/voice/message-idempotency-check`,
    headers: {
      'x-service-key': SERVICE_KEY,
      'Content-Type': 'application/json',
    },
    body: {
      provider_message_id: providerMessageId,
      org_id: orgId,
    },
    json: true,
    timeout: 3000,
  });
  return [{
    json: {
      ...parsed,
      org_id: orgId || parsed.org_id,
      org_nombre: org?.org_nombre || parsed.org_nombre,
      is_duplicate: resp?.is_duplicate === true,
    },
  }];
} catch (err) {
  const errMsg = String((err && err.message) ? err.message : err).slice(0, 120);
  return [{
    json: {
      ...parsed,
      org_id: orgId || parsed.org_id,
      org_nombre: org?.org_nombre || parsed.org_nombre,
      is_duplicate: false,
      idempotency_check_error: errMsg,
    },
  }];
}

// bot_state_machine_v1 — terminal stop for duplicate message
// El webhook ya respondió 200 al recibir; no enviamos nada a Meta
// para evitar duplicar el mensaje al usuario final.
return [{ json: { stopped: true, reason: 'duplicate_message' } }];

// bot_state_machine_v1 — Resolver Chat State (Parsear Mensaje / Buscar Org Texto)
//
// GET al backend para recuperar el state previo (last_view, last_listado,
// current_doc, last_intent). Inyecta los campos al item preservando upstream.
//
// Fail-open: si la API cae, previous_state queda como null y el agente
// trabaja sin contexto previo.
const APP_URL = $env.APP_URL;
const SERVICE_KEY = $env.FACTURAIA_SERVICE_KEY;
const parsed = $('Parsear Mensaje').first().json;
const org = $('Buscar Org Texto').first().json;

// phone_e164_normalize_v1: añadir '+' si falta — endpoint exige E.164.
const _phRaw = (parsed.normalized_phone || '').trim();
const phoneUser = _phRaw && !_phRaw.startsWith('+') ? '+' + _phRaw.replace(/^\++/, '') : _phRaw;
const phoneReceptorId = parsed.phone_number_id || '';
const orgId = org?.org_id || parsed.org_id || '';

if (!APP_URL || !SERVICE_KEY || !phoneUser || !orgId) {
  return [{
    json: {
      ...parsed,
      org_id: orgId,
      org_nombre: org?.org_nombre || parsed.org_nombre,
      previous_state: null,
      previous_state_json: null,
    },
  }];
}

try {
  const qs = new URLSearchParams({
    phone_user: phoneUser,
    phone_receptor_id: phoneReceptorId,
    org_id: orgId,
  }).toString();
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url: `${APP_URL}/api/internal/voice/chat-state?${qs}`,
    headers: {
      'x-service-key': SERVICE_KEY,
    },
    json: true,
    timeout: 3000,
  });
  return [{
    json: {
      ...parsed,
      org_id: orgId,
      org_nombre: org?.org_nombre || parsed.org_nombre,
      previous_state: resp?.current_view ?? null,
      previous_state_json: resp?.state_json ?? null,
    },
  }];
} catch (err) {
  const errMsg = String((err && err.message) ? err.message : err).slice(0, 120);
  return [{
    json: {
      ...parsed,
      org_id: orgId,
      org_nombre: org?.org_nombre || parsed.org_nombre,
      previous_state: null,
      previous_state_json: null,
      chat_state_resolve_error: errMsg,
    },
  }];
}

// bot_state_machine_v1 — tool consultar_presupuesto_detalle
//
// Devuelve detalle completo de un presupuesto (líneas, cliente, total, notas)
// pre-formateado para WhatsApp. El agente la usa cuando el user pide "qué
// tiene el 1" / "más detalle del 2" sobre el último listado.
const APP_URL = $env.APP_URL;
const SERVICE_KEY = $env.FACTURAIA_SERVICE_KEY;
const orgId = $('Preparar Input Agente').first().json.org_id;
const presupuestoId = $fromAI('presupuesto_id', 'UUID del presupuesto sobre el que se quiere ver detalle');

const resp = await this.helpers.httpRequest({
  method: 'POST',
  url: `${APP_URL}/api/internal/voice/presupuesto-detalle`,
  headers: {
    'x-service-key': SERVICE_KEY,
    'Content-Type': 'application/json',
  },
  body: { presupuesto_id: presupuestoId, org_id: orgId },
  json: true,
  timeout: 5000,
});

return JSON.stringify(resp || {});

// bot_state_machine_v1 — Persistir Chat State Doc
//
// Tras enviar PDF al usuario, persiste estado `post_action` con info del
// documento entregado. Fail-open: si falla, sólo log error, no rompe flujo.
const APP_URL = $env.APP_URL;
const SERVICE_KEY = $env.FACTURAIA_SERVICE_KEY;
const agentInput = $('Preparar Input Agente').first().json;
// phone_e164_normalize_v1: añadir '+' si falta — endpoint exige E.164.
const _phRaw = (agentInput.normalized_phone || agentInput.sessionId || '').trim();
const phoneUser = _phRaw && !_phRaw.startsWith('+') ? '+' + _phRaw.replace(/^\++/, '') : _phRaw;
const phoneReceptorId = agentInput.phone_number_id || '';
const orgId = agentInput.org_id || '';

// Best-effort: tomar info del doc del nodo de generación si existe.
let docInfo = null;
try {
  const gen = $('Generar Factura').first().json;
  docInfo = {
    tipo: gen?.tipo || null,
    id: gen?.id || gen?.factura_id || null,
    num: gen?.num || null,
  };
} catch (_e) {
  docInfo = null;
}

if (!APP_URL || !SERVICE_KEY || !phoneUser || !phoneReceptorId || !orgId) {
  return [{ json: { ...$json, persist_skipped: true } }];
}

try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: `${APP_URL}/api/internal/voice/chat-state`,
    headers: {
      'x-service-key': SERVICE_KEY,
      'Content-Type': 'application/json',
    },
    body: {
      phone_user: phoneUser,
      phone_receptor_id: phoneReceptorId,
      org_id: orgId,
      current_view: 'post_action',
      state_json: {
        current_doc: docInfo,
        last_intent: 'generar',
        ts: new Date().toISOString(),
      },
    },
    json: true,
    timeout: 3000,
  });
} catch (err) {
  // fail-open
}

return [{ json: $json }];

