// phone_e164_normalize_v1 + state_machine_v1 — Resolver Chat State (rama sesión voz activa)
//
// La rama 'Check Sesion Voz Activa → Tiene Sesion? → Preparar Input Correccion'
// no pasa por los resolvers voz/texto principales. Sin este resolver el LLM
// pierde acceso a previous_state.last_listado, last_doc, etc.
const APP_URL = $env.APP_URL;
const SERVICE_KEY = $env.FACTURAIA_SERVICE_KEY;
const upstream = $json;

const _phRaw = (upstream.normalized_phone || upstream.sessionId || '').trim();
const phoneUser = _phRaw && !_phRaw.startsWith('+') ? '+' + _phRaw.replace(/^\++/, '') : _phRaw;
const phoneReceptorId = upstream.phone_number_id || '';
const orgId = upstream.org_id || '';

if (!APP_URL || !SERVICE_KEY || !phoneUser || !phoneReceptorId || !orgId) {
  return [{ json: { ...upstream, previous_state: null, previous_state_json: null } }];
}

try {
  const qs = new URLSearchParams({
    phone_user: phoneUser,
    phone_receptor_id: phoneReceptorId,
    org_id: orgId,
  }).toString();
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url: `${APP_URL}/api/internal/voice/chat-state?${qs}`,
    headers: { 'x-service-key': SERVICE_KEY },
    json: true,
    timeout: 3000,
  });
  return [{ json: {
    ...upstream,
    previous_state: resp?.current_view ?? null,
    previous_state_json: resp?.state_json ?? null,
  } }];
} catch (err) {
  const errMsg = String((err && err.message) ? err.message : err).slice(0, 120);
  return [{ json: {
    ...upstream,
    previous_state: null,
    previous_state_json: null,
    chat_state_resolve_error: errMsg,
  } }];
}
